import React from 'react';

const Navbar = () => {
  return (
    <nav className="bg-white border-b border-slate-100 sticky top-0 z-50">
      <div className="container mx-auto px-6 py-4 flex justify-between items-center">
        <div className="text-xl font-bold text-slate-900 tracking-tight">
          MARIBEL <span className="text-blue-600">PROPIEDADES</span>
        </div>
        <div className="hidden md:flex items-center gap-6">
          <span className="text-[10px] bg-slate-100 text-slate-500 px-2 py-1 rounded-full font-bold">
            REGISTRO PN-XXXX-MVCS
          </span>
          <a href="https://wa.me/51900000000" target="_blank" rel="noreferrer" className="bg-slate-900 text-white px-5 py-2 rounded-lg text-sm font-semibold hover:bg-blue-600 transition">
            Contactar
          </a>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
